import{_ as a,H as l,f as e,i as r}from"./chunks/framework.eFU6Tutu.js";const c=JSON.parse('{"title":"Укроп","description":"","frontmatter":{},"headers":[],"relativePath":"plants/dill.md","filePath":"plants/dill.md"}'),i={name:"plants/dill.md"};function n(s,t,d,o,h,f){return l(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="укроп" tabindex="-1">Укроп <a class="header-anchor" href="#укроп" aria-label="Permalink to &quot;Укроп&quot;">​</a></h1><p>Укроп — одна из самых популярных пряных культур, которую можно успешно выращивать на подоконнике круглый год. Его ароматная зелень богата витаминами и придаёт свежий вкус салатам, супам и горячим блюдам.</p><h2 id="описание" tabindex="-1">Описание <a class="header-anchor" href="#описание" aria-label="Permalink to &quot;Описание&quot;">​</a></h2><p>Укроп — однолетнее травянистое растение семейства Зонтичные. Стебель прямостоячий, ветвистый, высотой до 40-50 см (в домашних условиях обычно ниже). Листья ажурные, многократно рассечённые, от ярко-зелёного до синевато-зелёного цвета. Семена имеют плотную оболочку, богатую эфирными маслами, что замедляет их прорастание.</p><h2 id="популярные-сорта-для-дома" tabindex="-1">Популярные сорта для дома <a class="header-anchor" href="#популярные-сорта-для-дома" aria-label="Permalink to &quot;Популярные сорта для дома&quot;">​</a></h2><p>Для подоконника подходят компактные, желательно позднеспелые сорта, которые дольше не зацветают и дают больше зелени.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Сорт</th><th style="text-align:left;">Характеристика</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Грибовский</strong></td><td style="text-align:left;">Раннеспелый, неприхотливый, ароматный</td></tr><tr><td style="text-align:left;"><strong>Гренадер</strong></td><td style="text-align:left;">Раннеспелый, ярко-зелёный, устойчив к вредителям</td></tr><tr><td style="text-align:left;"><strong>Кибрай</strong></td><td style="text-align:left;">Позднеспелый, компактный куст, долго не грубеет, очень ароматный</td></tr><tr><td style="text-align:left;"><strong>Салют</strong></td><td style="text-align:left;">Позднеспелый, мощный куст с крупными листьями, устойчив к болезням</td></tr><tr><td style="text-align:left;"><strong>Аллигатор</strong></td><td style="text-align:left;">Среднепоздний, неприхотливый, устойчив к пожелтению</td></tr><tr><td style="text-align:left;"><strong>Ришелье</strong></td><td style="text-align:left;">Среднеспелый, декоративный, с синевато-зелёными ажурными листьями</td></tr></tbody></table><h2 id="уход" tabindex="-1">Уход <a class="header-anchor" href="#уход" aria-label="Permalink to &quot;Уход&quot;">​</a></h2><p>Подробнее об уходе за укропом и другой зеленью читайте в <a href="/care/greens/#укроп">гайде по уходу за зеленью</a>.</p><h2 id="как-использовать-в-еде" tabindex="-1">Как использовать в еде <a class="header-anchor" href="#как-использовать-в-еде" aria-label="Permalink to &quot;Как использовать в еде&quot;">​</a></h2><ul><li>Свежие салаты (особенно с огурцами и помидорами)</li><li>Посыпка для супов и борщей</li><li>Добавка в горячие блюда (картофель, мясо, рыба)</li><li>Домашние соленья и консервация</li><li>Творог и яйца с укропом</li><li>Заморозка и сушка на зиму</li></ul><h2 id="полезные-своиства" tabindex="-1">Полезные свойства <a class="header-anchor" href="#полезные-своиства" aria-label="Permalink to &quot;Полезные свойства&quot;">​</a></h2><ul><li>Богат витаминами С, А, РР, группы В</li><li>Содержит калий, кальций, железо и фосфор</li><li>Нормализует пищеварение и улучшает аппетит</li><li>Обладает мягким мочегонным и ветрогонным действием</li><li>Полезен для иммунитета и зрения</li></ul><h2 id="источники-информации" tabindex="-1">Источники информации <a class="header-anchor" href="#источники-информации" aria-label="Permalink to &quot;Источники информации&quot;">​</a></h2><ul><li><a href="https://pogoda.mail.ru/news/62649136/" target="_blank" rel="noreferrer">Погода Mail — Укроп на подоконнике</a></li><li><a href="https://antonovsad.ru/zelen-na-podokonnike-13-kultur-dlya-vyrashchivaniya-6747/" target="_blank" rel="noreferrer">Антонов сад — 13 культур для выращивания</a></li></ul><h2 id="похожие-растения" tabindex="-1">Похожие растения <a class="header-anchor" href="#похожие-растения" aria-label="Permalink to &quot;Похожие растения&quot;">​</a></h2><ul><li><a href="/plants/parsley.html">Петрушка</a></li><li><a href="/plants/salad.html">Салаты</a></li><li><a href="/plants/basil.html">Базилик</a></li><li><a href="/plants/chives.html">Лук (зелёный)</a></li></ul>',17)])])}const g=a(i,[["render",n]]);export{c as __pageData,g as default};
